1612   // If costs are equal, still fold as we reduce instruction count.
1613   if (NewCost > OldCost)
1614     return false;
1615 
1616   Value *Shuf0 = Builder.CreateShuffleVector(Op00, Op01, NewMask0);
1617   Value *Shuf1 = Builder.CreateShuffleVector(Op10, Op11, NewMask1);
1618   Value *NewBO = Builder.CreateBinOp(Opcode, Shuf0, Shuf1);
1619 
1620   // Intersect flags from the old binops.
1621   if (auto *NewInst = dyn_cast<Instruction>(NewBO))
1622     NewInst->copyIRFlags(BinOp);
1623 
1624   Worklist.pushValue(Shuf0);
1625   Worklist.pushValue(Shuf1);
1626   replaceValue(I, *NewBO);
1627   return true;
1628 }
