178 bool VectorCombine::vectorizeLoadInsert(Instruction &I) {
179   // Match insert into fixed vector of scalar value.
180   // TODO: Handle non-zero insert index.
181   Value *Scalar;
182   if (!match(&I,
183              m_InsertElt(m_Poison(), m_OneUse(m_Value(Scalar)), m_ZeroInt())))
184     return false;
185 
186   // Optionally match an extract from another vector.
187   Value *X;
188   bool HasExtract = match(Scalar, m_ExtractElt(m_Value(X), m_ZeroInt()));
189   if (!HasExtract)
190     X = Scalar;
191 
192   auto *Load = dyn_cast<LoadInst>(X);
193   if (!canWidenLoad(Load, TTI))
194     return false;
195 
196   Type *ScalarTy = Scalar->getType();
197   uint64_t ScalarSize = ScalarTy->getPrimitiveSizeInBits();
198   unsigned MinVectorSize = TTI.getMinVectorRegisterBitWidth();
199 
200   // Check safety of replacing the scalar load with a larger vector load.
201   // We use minimal alignment (maximum flexibility) because we only care about
202   // the dereferenceable region. When calculating cost and creating a new op,
203   // we may use a larger value based on alignment attributes.
204   Value *SrcPtr = Load->getPointerOperand()->stripPointerCasts();
205   assert(isa<PointerType>(SrcPtr->getType()) && "Expected a pointer type");
206 
207   unsigned MinVecNumElts = MinVectorSize / ScalarSize;
208   auto *MinVecTy = VectorType::get(ScalarTy, MinVecNumElts, false);
209   unsigned OffsetEltIndex = 0;
210   Align Alignment = Load->getAlign();
211   if (!isSafeToLoadUnconditionally(SrcPtr, MinVecTy, Align(1), *DL, Load, &AC,
212                                    &DT)) {
213     // It is not safe to load directly from the pointer, but we can still peek
214     // through gep offsets and check if it safe to load from a base address with
215     // updated alignment. If it is, we can shuffle the element(s) into place
216     // after loading.
217     unsigned OffsetBitWidth = DL->getIndexTypeSizeInBits(SrcPtr->getType());
218     APInt Offset(OffsetBitWidth, 0);
219     SrcPtr = SrcPtr->stripAndAccumulateInBoundsConstantOffsets(*DL, Offset);
220 
221     // We want to shuffle the result down from a high element of a vector, so
222     // the offset must be positive.
223     if (Offset.isNegative())
224       return false;
225 
226     // The offset must be a multiple of the scalar element to shuffle cleanly
227     // in the element's size.
228     uint64_t ScalarSizeInBytes = ScalarSize / 8;
229     if (Offset.urem(ScalarSizeInBytes) != 0)
230       return false;
231 
232     // If we load MinVecNumElts, will our target element still be loaded?
233     OffsetEltIndex = Offset.udiv(ScalarSizeInBytes).getZExtValue();
234     if (OffsetEltIndex >= MinVecNumElts)
235       return false;
236 
237     if (!isSafeToLoadUnconditionally(SrcPtr, MinVecTy, Align(1), *DL, Load, &AC,
238                                      &DT))
239       return false;
240 
241     // Update alignment with offset value. Note that the offset could be negated
242     // to more accurately represent "(new) SrcPtr - Offset = (old) SrcPtr", but
243     // negation does not change the result of the alignment calculation.
244     Alignment = commonAlignment(Alignment, Offset.getZExtValue());
245   }
246 
247   // Original pattern: insertelt undef, load [free casts of] PtrOp, 0
248   // Use the greater of the alignment on the load or its source pointer.
249   Alignment = std::max(SrcPtr->getPointerAlignment(*DL), Alignment);
250   Type *LoadTy = Load->getType();
