1697 /// Matches instructions with Opcode and three operands.
1698 template <typename T0, typename T1, unsigned Opcode> struct TwoOps_match {
1699   T0 Op1;
1700   T1 Op2;
1701 
1702   TwoOps_match(const T0 &Op1, const T1 &Op2) : Op1(Op1), Op2(Op2) {}
1703 
1704   template <typename OpTy> bool match(OpTy *V) {
1705     if (V->getValueID() == Value::InstructionVal + Opcode) {
1706       auto *I = cast<Instruction>(V);
1707       return Op1.match(I->getOperand(0)) && Op2.match(I->getOperand(1));
