1764   auto *CastDstTy = dyn_cast<FixedVectorType>(C0->getDestTy());
1765   auto *CastSrcTy = dyn_cast<FixedVectorType>(C0->getSrcTy());
1766   if (!ShuffleDstTy || !CastDstTy || !CastSrcTy)
